// Usage in app
public async Task CheckPlatformCapabilitiesAsync()
{
    var capabilities = DependencyService.Get<IPlatformCapabilities>();

    if (!capabilities.SupportsSecureStorage)
    {
        // Use alternative authentication method
        await UseTokenFileStorageAsync();
    }

    if (!capabilities.SupportsNotifications)
    {
        // Disable notification features
        NotificationButton.IsVisible = false;
    }

    // Show detailed report in settings
    var report = await capabilities.GetDetailedReportAsync();
    CapabilityReportLabel.Text = FormatReport(report);
}
